vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    ret = texture(sampler_main,vUv).xyz;

    float bl = GetBlur2(vUv);
    vec2 tex = bl*ret.xyz;

    ret *= 2.4;
    ret *= texture(sampler_main, bl+tex);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;

  fragColor = ret;
}
